import Foundation

/// The Qwen3.6 (`qwen3_5` family) chat-template fix.
///
/// The stock Qwen3.6 chat template raises `No user query found in messages` — an HTTP 500
/// at prompt-render time — whenever a conversation has no plain user turn (after context
/// compaction, or in deep agentic tool-loops). mtplx's default `--chat-template-profile
/// local_qwen36` uses the model's own (buggy) template, so the fix is to launch the daemon
/// with `--chat-template-path` pointing at a guard-free "hardened" template we ship.
///
/// Verified live on dense (27B) + MoE (35B-A3B): the 500 is gone and tool-calling is intact
/// (mtplx's hybrid tool contract is independent of the chat template).
enum QwenTemplateFix {
    static var dir: URL {
        FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask)[0]
            .appendingPathComponent("MTPLX Router/templates", isDirectory: true)
    }
    static var templateURL: URL { dir.appendingPathComponent("qwen36_hardened.jinja") }
    static var templatePath: String { templateURL.path }

    /// Write the embedded hardened template to disk if missing. Idempotent; never clobbers
    /// an existing file (so a hand-verified template is preserved).
    static func ensureInstalled() {
        if FileManager.default.fileExists(atPath: templateURL.path) { return }
        guard let data = Data(base64Encoded: embeddedB64) else { return }
        try? FileManager.default.createDirectory(at: dir, withIntermediateDirectories: true)
        try? data.write(to: templateURL)
    }

    /// True when the model at `modelPath` is the Qwen3.5/3.6 family — dense `qwen3_5` or
    /// MoE `qwen3_5_moe` — i.e. the lineage whose stock template carries the buggy guard.
    static func isQwen35(modelPath: String) -> Bool {
        let cfg = URL(fileURLWithPath: modelPath).appendingPathComponent("config.json")
        guard let data = try? Data(contentsOf: cfg),
              let obj = (try? JSONSerialization.jsonObject(with: data)) as? [String: Any]
        else { return false }
        if let mt = obj["model_type"] as? String, mt.lowercased().hasPrefix("qwen3_5") { return true }
        if let arch = obj["architectures"] as? [String],
           arch.contains(where: { $0.lowercased().hasPrefix("qwen3_5") }) { return true }
        return false
    }

    /// base64 of the verified hardened template (sha256 060354fe…), decoded on first launch.
    static let embeddedB64 = ""
}
